create table dirkspzm32.s_erp_rcv_fa_auf (
    sid                         varchar2(50 char) not null enable,
    firma_nr                    number(3, 0) not null enable,
    auf_id                      number(*, 0) not null enable,
    auftrag                     varchar2(20 char),
    leitzahl                    number(*, 5),
    fa_ag                       number(*, 5),
    fa_upos                     number(*, 5),
    satzart                     varchar2(2 char),
    maschine                    varchar2(25 char),
    ab_artikel                  varchar2(30 char),
    ab_soll                     number(12, 3),
    ab_ist                      number(12, 3),
    ab_status                   varchar2(3 char),
    ab_text1                    varchar2(255 char),
    ab_text2                    varchar2(255 char),
    ab_text3                    varchar2(255 char),
    ag_prod_frei                varchar2(1 char),
    ag_artikel                  varchar2(30 char),
    ag_art_laenge               number(12, 3),
    ag_art_breite               number(12, 3),
    ag_art_dicke                number(12, 3),
    ag_art_durch                number(12, 3),
    ag_bez1                     varchar2(255 char),
    ag_bez2                     varchar2(255 char),
    ag_text1                    varchar2(255 char),
    ag_text2                    varchar2(255 char),
    ag_text3                    varchar2(255 char),
    ag_freigabe_st              number(3, 0),
    ag_status                   varchar2(3 char),
    ag_soll_mg                  number(12, 3),
    ag_ist_mg                   number(12, 3),
    ag_ist_mg_b                 number(12, 3),
    ag_ist_schrott              number(12, 3),
    ag_ist_ruesten              number(12, 3),
    ag_ueberlappen              number(12, 3),
    prod_param                  clob,
    ruest_zeit_gepl             number(18, 9),
    ruest_zeit_ist              number(18, 9),
    prod_zeit_gepl              number(18, 9),
    prod_zeit_ist               number(18, 9),
    nutzen                      number(10, 5),
    gewicht                     number(11, 5),
    schrott                     number(11, 5),
    verbrauch                   number(11, 5),
    einsatz                     number(11, 5),
    stoer_zeit_gepl             number(18, 9),
    stoer_zeit_ist              number(18, 9),
    zeit_einheit                number(18, 9),
    start_gepl                  date,
    start_ist                   date,
    ende_gepl                   date,
    ende_ist                    date,
    zeichnung                   varchar2(30 char),
    zeichnung_index             varchar2(2 char),
    fremd_zeichnung             varchar2(30 char),
    zeichnungname               varchar2(255 char),
    max_tak_ausf_zeit           number(18, 9),
    max_tak_zeit                number(18, 9),
    min_tak_zeit                number(18, 9),
    charge                      varchar2(60 char),
    lhm_name                    varchar2(50 char),
    lhm_menge                   number(*, 5),
    lte_name                    varchar2(22 char),
    lte_menge                   number(*, 5),
    kunden_nr                   varchar2(20 char),
    kunden_ab                   varchar2(20 char),
    kunden_ab_pos               varchar2(20 char),
    kunden_ab_upos              varchar2(20 char),
    best_nr_kunde               varchar2(30 char),
    term_wunsch                 date,
    term_best                   date,
    transp_zeit                 number(5, 0),
    kenz_lhm_druck              varchar2(1 char),
    anz_rohstoffe               number(3, 0),
    ausgef_ende                 varchar2(1 char),
    rcv_ag_ist_mg               number(*, 3),
    rcv_ag_ist_mg_b             number(*, 3),
    rcv_ag_ist_mg_schrott       number(*, 3),
    rcv_ag_ist_mg_ruesten       number(*, 3),
    rcv_ruest_zeit_ist          number(*, 5),
    rcv_prod_zeit_ist           number(*, 5),
    rcv_stoer_zeit_ist          number(*, 5),
    ag_los_mg                   number(*, 3),
    prioritaet                  varchar2(20 char),
    ts                          date,
    tsc                         date,
    vorgangsqualifikation       varchar2(50 char),
    anz_mitarbeiter             number(*, 5),
    lueckenfueller              varchar2(1 char),
    kunden_ab_wechsel_ruestzeit number(*, 5),
    start_batch_by_order_start  varchar2(200 char),
    ext_arbeits_anweisung       varchar2(200 char),
    kunden_ab_text              varchar2(255 char),
    kategorie                   varchar2(20 char),
    seq_nr                      number,
    lead_leitzahl               number,
    primaer_leitzahl            number
);

alter table dirkspzm32.s_erp_rcv_fa_auf
    add constraint pk_s_erp_rcv_res_fa_auftrag
        primary key ( sid,
                      firma_nr,
                      auf_id )
            using index enable;


